#ifndef XPCOMComponentExample_h_
#define XPCOMComponentExample_h_

#include "nsCOMPtr.h"
#include "nsIObserver.h"
#include "nsIObserverService.h"

/**
 * XPCOMComponentExample is a simple XPCOM component that implements
 * the nsIObserver interface to listen for system notifications.
 *
 * This component demonstrates the standard Firefox XPCOM patterns:
 * - Use of NS_DECL_ISUPPORTS for reference counting
 * - Use of NS_DECL_NSIOBSERVER for observer interface
 * - Proper QueryInterface, AddRef, and Release implementations
 * - Registration using NS_GENERIC_FACTORY_CONSTRUCTOR
 */
class XPCOMComponentExample : public nsIObserver {
 public:
  NS_DECL_ISUPPORTS
  NS_DECL_NSIOBSERVER

  XPCOMComponentExample();

  /**
   * Initialize the component by registering with the observer service.
   * This method is called during component creation.
   */
  nsresult Init();

 protected:
  virtual ~XPCOMComponentExample() = default;

 private:
  nsCOMPtr<nsIObserverService> mObserverService;
};

#endif /* XPCOMComponentExample_h_ */

/* -*- Mode: C++; tab-width: 2; indent-tabs-mode: nil; c-basic-offset: 2 -*- */
/* This Source Code Form is subject to the terms of the Mozilla Public
