 * file, You can obtain one at http://mozilla.org/MPL/2.0/. */

#include "XPCOMComponentExample.h"

#include "mozilla/Services.h"
#include "nsServiceManagerUtils.h"

// Implement the three required XPCOM methods: QueryInterface, AddRef, Release.
// NS_IMPL_ISUPPORTS macro generates the standard reference counting implementation
// that handles interface querying and reference counting for all specified interfaces.
NS_IMPL_ISUPPORTS(XPCOMComponentExample, nsIObserver)

XPCOMComponentExample::XPCOMComponentExample() : mObserverService(nullptr) {}

nsresult XPCOMComponentExample::Init() {
  // Get the observer service to register for notifications
  mObserverService = mozilla::services::GetObserverService();
  if (!mObserverService) {
    return NS_ERROR_FAILURE;
  }

  // Register to observe the xpcom-shutdown topic so we can clean up properly
  nsresult rv = mObserverService->AddObserver(this, "xpcom-shutdown", false);
  if (NS_FAILED(rv)) {
    return rv;
  }

  return NS_OK;
}

// Implementation of the Observe method from nsIObserver interface.
// This method is called whenever a notification for a registered topic is posted.
// The NS_DECL_NSIOBSERVER macro in the header file declares this method,
// and we must implement it here with the signature:
// NS_IMETHODIMP Observe(nsISupports* aSubject, const char* aTopic, const char16_t* aData)
NS_IMETHODIMP
XPCOMComponentExample::Observe(nsISupports* aSubject, const char* aTopic,
                               const char16_t* aData) {
  // Handle different notification topics
  if (strcmp(aTopic, "xpcom-shutdown") == 0) {
    // Clean up during shutdown
    if (mObserverService) {
      mObserverService->RemoveObserver(this, "xpcom-shutdown");
      mObserverService = nullptr;
    }
    return NS_OK;
  }

  // Return NS_OK for unhandled topics
  return NS_OK;
}

// NS_GENERIC_FACTORY_CONSTRUCTOR_INIT macro generates a factory function that:
// 1. Creates a new instance of XPCOMComponentExample
// 2. Calls the Init() method to initialize the component
// 3. Calls QueryInterface to get the requested interface pointer
// This approach ensures proper initialization before the component is used.
NS_GENERIC_FACTORY_CONSTRUCTOR_INIT(XPCOMComponentExample, Init)

